#include "register/op_def_registry.h"

namespace optiling {

static constexpr uint32_t MAX_BLOCK_DIM = 24;
static constexpr uint32_t MIN_BLOCK_DIM = 4;

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Ca6k00358CustomTilingData tiling;
    const gert::StorageShape* xShape = context->GetInputShape(0);
    uint32_t n = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(0));
    uint32_t c = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(1));
    uint32_t h = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(2));
    uint32_t w = static_cast<uint32_t>(xShape->GetOriginShape().GetDim(3));

    const gert::RuntimeAttrs* attrs = context->GetAttrs();
    int64_t outputHeight = *attrs->GetInt(0);
    int64_t outputWidth  = *attrs->GetInt(1);

    uint32_t outH = static_cast<uint32_t>(outputHeight);
    uint32_t outW = static_cast<uint32_t>(outputWidth);
    uint32_t totalOutput = n * c * outH * outW;

    uint32_t blockDim = totalOutput / 4096;
    if (blockDim < MIN_BLOCK_DIM) blockDim = MIN_BLOCK_DIM;
    if (blockDim > MAX_BLOCK_DIM) blockDim = MAX_BLOCK_DIM;

    context->SetBlockDim(blockDim);

    tiling.set_totalOutputElems(totalOutput);
    tiling.set_inN(n);
    tiling.set_inC(c);
    tiling.set_inH(h);
    tiling.set_inW(w);
    tiling.set_outH(outH);
    tiling.set_outW(outW);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

